class Solution:
    def racecar(self, target):
        from collections import deque
        start = (0, 1)
        q = deque([(0, 0, 1)])
        seen = {start}
        limit = 2 * target + 2
        while q:
            steps, pos, speed = q.popleft()
            if pos == target:
                return steps
            np, ns = pos + speed, speed * 2
            if abs(np) <= limit and (np, ns) not in seen:
                seen.add((np, ns))
                q.append((steps + 1, np, ns))
            rs = -1 if speed > 0 else 1
            if (pos, rs) not in seen:
                seen.add((pos, rs))
                q.append((steps + 1, pos, rs))
        return -1

