class Solution:
    def racecar(self, target):
        dp = [0] * (target + 1)
        for t in range(1, target + 1):
            k = t.bit_length()
            if (1 << k) - 1 == t:
                dp[t] = k
                continue
            best = k + 1 + dp[(1 << k) - 1 - t]
            for j in range(k - 1):
                rem = t - ((1 << (k - 1)) - (1 << j))
                best = min(best, (k - 1) + j + 2 + dp[rem])
            dp[t] = best
        return dp[target]

