var racecar = function(target) {
    const dp = new Array(target + 1).fill(0);
    for (let t = 1; t <= target; t++) {
        let k = 0;
        while ((1 << (k + 1)) - 1 < t) k++;
        k++;
        if ((1 << k) - 1 === t) {
            dp[t] = k;
            continue;
        }
        let best = k + 1 + dp[(1 << k) - 1 - t];
        for (let j = 0; j < k - 1; j++) {
            const rem = t - ((1 << (k - 1)) - (1 << j));
            best = Math.min(best, (k - 1) + j + 2 + dp[rem]);
        }
        dp[t] = best;
    }
    return dp[target];
};
